# Hybrid search: BM25 + dense with RRF and cross-encoder reranking
import math
from typing import List, Tuple

class HybridRetriever:
    def __init__(self, dense_retriever, bm25_retriever, reranker=None):
        self.dense = dense_retriever    # Cosine similarity on embeddings
        self.bm25 = bm25_retriever       # Sparse term-frequency index
        self.reranker = reranker          # Cross-encoder (optional)

    def reciprocal_rank_fusion(self, dense_results: List[str],
                               bm25_results: List[str], k: int = 60) -> List[Tuple[str, float]]:
        """Fuse two ranked lists using RRF."""
        scores = {}
        for rank, doc in enumerate(dense_results):
            scores[doc] = scores.get(doc, 0) + 1 / (k + rank + 1)
        for rank, doc in enumerate(bm25_results):
            scores[doc] = scores.get(doc, 0) + 1 / (k + rank + 1)
        return sorted(scores.items(), key=lambda x: -x[1])

    def search(self, query: str, top_k: int = 5):
        # Stage 1: parallel dense + sparse retrieval
        dense_top = self.dense.search(query, k=100)
        bm25_top = self.bm25.search(query, k=100)
        # Stage 2: RRF fusion → top-50
        fused = self.reciprocal_rank_fusion(dense_top, bm25_top)[:50]
        # Stage 3: cross-encoder reranking on top-50
        if self.reranker:
            reranked = self.reranker.rerank(query, [d for d, _ in fused])
            return reranked[:top_k]
        return [d for d, _ in fused[:top_k]]

# Staff insight: BM25 + dense RRF catches >95% of recall gaps
# Cross-encoder improves ranking precision but costs 2-10ms per pair

# RAG evaluation — retrieval + generation metrics
import numpy as np

class RAGEvaluator:
    def __init__(self, rag_system, eval_queries, ground_truth):
        self.rag = rag_system
        self.queries = eval_queries
        self.ground_truth = ground_truth  # List of (relevant_passage_ids, expected_answer)

    def hit_rate_at_k(self, k: int = 5) -> float:
        hits = 0
        for query, (gt_ids, _) in zip(self.queries, self.ground_truth):
            retrieved = self.rag.retrieve(query, k=k)
            if any(doc_id in gt_ids for doc_id in retrieved):
                hits += 1
        return hits / len(self.queries)

    def faithfulness_score(self, questions, answers, contexts) -> float:
        """Simplified faithfulness: fraction of answer claims supported by context."""
        # In production, use LLM-as-judge or RAGAS
        scores = []
        for answer, context in zip(answers, contexts):
            claims = answer.split(". ")  # Naive claim decomposition
            supported = sum(1 for c in claims if any(c[:20] in ctx for ctx in context))
            scores.append(supported / max(len(claims), 1))
        return np.mean(scores)

    def full_report(self):
        print(f"Hit Rate @5:   {self.hit_rate_at_k(5):.0%}")
        print(f"MRR:          {self.mean_reciprocal_rank():.3f}")
        print(f"NDCG@10:      {self.ndcg_at_k(10):.3f}")
        answers = [self.rag.answer(q) for q in self.queries]
        contexts = [self.rag.retrieve(q, k=3) for q in self.queries]
        print(f"Faithfulness: {self.faithfulness_score(self.queries, answers, contexts):.0%}")

# ponytail: RAGAS uses LLM-as-judge for faithfulness; cost is ~$0.01 per eval query.
# For 500 queries, budget $5 — well worth it before a production deployment.

# Production RAG at scale — caching, query rewriting, multi-hop
import hashlib, time
from collections import OrderedDict

class SemanticCache:
    def __init__(self, max_entries: int = 1_000_000, threshold: float = 0.95):
        self.cache = OrderedDict()   # query_embedding -> cached_response
        self.max_entries = max_entries
        self.threshold = threshold    # Cosine sim threshold for cache hit
        self.hits = self.misses = 0

    def get(self, query_emb: np.ndarray):
        for emb, response in reversed(list(self.cache.items())):
            sim = np.dot(query_emb, emb) / (
                np.linalg.norm(query_emb) * np.linalg.norm(emb) + 1e-8)
            if sim > self.threshold:
                self.cache.move_to_end(emb)
                self.hits += 1
                return response
        self.misses += 1
        return None

    def put(self, query_emb: np.ndarray, response: str):
        if len(self.cache) >= self.max_entries:
            self.cache.popitem(last=False)
        self.cache[tuple(query_emb.tolist())] = response

class MultiHopRAG:
    def __init__(self, retriever, llm, decomposer):
        self.retriever = retriever
        self.llm = llm
        self.decomposer = decomposer  # LLM that splits complex questions

    def answer(self, question: str) -> str:
        if self._is_simple(question):
            return self._fast_path(question)
        sub_questions = self.decomposer(f"Break this into sub-questions: {question}")
        contexts = []
        for sub_q in sub_questions.split("\n"):
            contexts.extend(self.retriever.search(sub_q.strip(), k=3))
        return self.llm.generate(self._format_context(contexts, question))

# ponytail: semantic cache with cos sim threshold trades 1% accuracy for 35% cost
# Hit rate target: 80%+ for embedding cache, 60%+ for semantic answer cache
